module full_adder(
    input obf_a,            // First 1-bit input signal.
    input b,            // Second 1-bit input signal.
    input cin,          // Carry-in 1-bit input signal.

    output sum,         // Sum output signal.
    output cout         // Carry-out output signal.
);

// Full adder logic
assign sum = obf_a ^ b ^ cin;
assign cout = (obf_a & b) | (b & cin) | (obf_a & cin);

endmodule
